func (qcb *QueueCreateBulk) OnConflictColumns(columns ...string) *QueueUpsertBulk {
	qcb.conflict = append(qcb.conflict, sql.ConflictColumns(columns...))
	return &QueueUpsertBulk{
		create: qcb,
	}
}

